INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ADV_1: Le email warm domain rotation: utiliser 3-5 domaines en rotation pour le cold email. Si 1 est blackliste, les autres continuent.', 'Domain rotation cold: 3-5 domaines. 1 blackliste = autres continuent', 'email', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_2: Le commercial mutual close plan doc: Google Doc partage avec le prospect: etapes, responsables, dates, decisions a prendre. Accelere le closing de 30%.', 'Mutual close plan Google Doc = -30% cycle closing', 'commercial', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_3: Le content hook testing method: poster le meme contenu avec 3 hooks differents sur 3 jours. Le hook avec le plus d engagement = gagnant. Le reutiliser.', 'Hook testing: 3 hooks × 3 jours. Meilleur engagement = gagnant', 'content', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_4: Le SEO content pruning ROI: supprimer ou fusionner les 20% d articles les moins performants ameliore le ranking des 80% restants de 15%.', 'Content pruning: supprimer 20% faibles = +15% ranking des 80% restants', 'seo', 'insight', 0.85, 'adv_pack', 'system'),
('ADV_5: Le ad attribution window: Meta default 7-day click + 1-day view. Changer a 28-day click pour les cycles de vente longs (SaaS, B2B).', 'Attribution window: 7d click default. 28d click pour SaaS/B2B cycles longs', 'ads', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_6: Le DM conversation depth indicator: si le prospect pose une question sur le prix ou les features = signal d achat fort. Proposer un RDV immediatement.', 'DM signal achat: question prix/features = proposer RDV immediatement', 'dm_instagram', 'insight', 0.85, 'adv_pack', 'system'),
('ADV_7: Le WhatsApp business analytics: taux de livraison, taux de lecture, taux de reponse par template. Optimiser les templates avec le meilleur taux de reponse.', 'WhatsApp analytics: livraison + lecture + reponse par template. Optimiser', 'whatsapp', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_8: Le chatbot A/B testing: tester 2 versions du meme flow (greeting different, nombre de questions, CTA different) et mesurer le taux de resolution.', 'Chatbot A/B: 2 versions flow → mesurer resolution → gagnant = defaut', 'chatbot', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_9: Le GMaps booking button: activer le bouton "Reserver" sur la fiche Google avec un lien vers votre systeme de reservation = +25% conversions directes.', 'GMaps bouton Reserver = +25% conversions directes', 'gmaps', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_10: Le TikTok duet strategy: faire un duet avec une video virale de sa niche en ajoutant de la valeur (commentaire expert, reaction, astuce). Surfe sur la viralite existante.', 'TikTok duet viral niche = surfer viralite existante + valeur ajoutee', 'tiktok_comments', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_11: Le CEO agent weekly priorities: chaque lundi, definir les 3 actions les plus impactantes pour la semaine. Communiquer aux agents concernes. Vendredi review.', 'CEO weekly: lundi 3 priorities → communiquer → vendredi review', 'ceo', 'best_practice', 0.88, 'adv_pack', 'system'),
('ADV_12: Le retention product stickiness: les features qui creent des donnees cumulatives (CRM rempli, contenu planifie, historique) augmentent le switching cost naturellement.', 'Stickiness: features donnees cumulatives = switching cost naturel', 'retention', 'insight', 0.85, 'adv_pack', 'system'),
('ADV_13: Le onboarding milestone rewards: chaque etape completee = micro-recompense (badge, confetti, message encourageant). Gamification = +40% completion.', 'Onboarding milestones: micro-recompense chaque etape = +40% completion', 'onboarding', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_14: Le comptable cash flow management: paiement annuel upfront = +40% cashflow. Paiement trimestriel = +20%. Mensuel = baseline. Encourager l annuel.', 'Cash flow: annuel +40%, trimestriel +20%, mensuel baseline. Encourager annuel', 'comptable', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_15: Le RH async communication policy: decision = ecrite (Notion). Discussion = Slack. Urgence = appel. Brainstorm = meeting. Chaque sujet a son canal.', 'Async policy: decision=ecrit, discussion=Slack, urgence=appel, brainstorm=meeting', 'rh', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_16: Le marketing competitive response framework: concurrent lance feature → analyser impact → si menace: communiquer notre avantage. Si pas menace: ignorer.', 'Competitive response: analyser impact. Menace=communiquer avantage. Pas menace=ignorer', 'marketing', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_17: Le cross-agent customer journey automation: signup → onboarding email J0 → content discovery J1 → feature education J3 → value check J7 → upgrade prompt J14.', 'Journey auto: signup→email J0→content J1→feature J3→check J7→upgrade J14', NULL, 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_18: Le prospect lifecycle management: lead → MQL (marketing qualified) → SQL (sales qualified) → opportunity → customer → advocate. Criteres clairs pour chaque transition.', 'Lifecycle: lead→MQL→SQL→opportunity→customer→advocate. Criteres clairs', NULL, 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_19: Le KeiroAI shared intelligence model: les apprentissages de chaque agent (templates gagnants, heures optimales, segments reactifs) sont stockes dans le RAG et accessibles a tous.', 'KeiroAI shared intelligence: apprentissages agents → RAG → accessibles a tous', NULL, 'best_practice', 0.90, 'adv_pack', 'system'),
('ADV_20: Le agent performance benchmarking: comparer les metriques de chaque agent aux benchmarks du secteur (OR email vs moyenne, engagement content vs moyenne).', 'Agent benchmark: metriques vs benchmarks secteur par agent', 'ceo', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_21: Le email subject line split test automation: pour chaque campagne, generer 5 subjects via IA → tester les 2 meilleurs sur 10% → gagnant aux 90%.', 'Subject split auto: 5 IA → test 2 sur 10% → gagnant aux 90%', 'email', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_22: Le commercial deal coaching: pour chaque deal strategique, un call hebdo de 15 min pour revoir: blocages, prochaines etapes, strategies specifiques.', 'Deal coaching: 15 min/sem/deal strategique. Blocages + next steps + strategies', 'commercial', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_23: Le content evergreen optimization: identifier les articles evergreen (trafic stable 6+ mois) et les mettre a jour tous les 6 mois avec des donnees fraiches.', 'Evergreen optimization: articles stables 6+ mois → MAJ tous 6 mois donnees fraiches', 'content', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_24: Le SEO entity optimization: mentionner les entites liees (noms, lieux, concepts, dates) dans le contenu aide Google a comprendre le sujet en profondeur.', 'Entity SEO: mentionner entites liees = comprehension Google en profondeur', 'seo', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_25: Le ad creative naming convention: [Date]_[Audience]_[Format]_[Angle]_[Variation]. Ex: 20260325_cold_video_pain_v2. Indispensable pour l analyse.', 'Creative naming: Date_Audience_Format_Angle_Variation. Indispensable analyse', 'ads', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_26: Le DM Instagram community building: au lieu de pitcher, construire une relation. Liker + commenter pendant 2 semaines avant le premier DM = 40% reponse.', 'DM community: 2 sem relation (like+comment) avant DM = 40% reponse', 'dm_instagram', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_27: Le WhatsApp catalog management: mettre a jour le catalogue produits toutes les semaines. Les produits avec photo + description + prix convertissent 3x mieux.', 'WhatsApp catalogue hebdo: photo + desc + prix = 3x conversion', 'whatsapp', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_28: Le chatbot multilingual: detecter la langue du visiteur et repondre dans sa langue. Les chatbots multilingues augmentent la satisfaction de 35%.', 'Chatbot multilingual: detecter langue visiteur → repondre dans sa langue = +35%', 'chatbot', 'insight', 0.78, 'adv_pack', 'system'),
('ADV_29: Le GMaps service area optimization: definir precisement les zones geographiques desservies. Elargir progressivement quand les avis s accumulent.', 'GMaps service area: definir zones precises. Elargir avec accumulation avis', 'gmaps', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_30: Le TikTok monetization path: 1K followers → live gifts. 10K → creator fund. 50K → brand deals. 100K+ → product launches. Chaque palier = nouveau revenu.', 'TikTok monetization: 1K live, 10K fund, 50K brand deals, 100K+ product launches', 'tiktok_comments', 'insight', 0.78, 'adv_pack', 'system'),
('ADV_31: Le CEO data-driven decision: pour chaque decision strategique, collecter 3 data points + 2 perspectives d agents differents + 1 intuition. Pas de decision basee sur 1 seul signal.', 'CEO decision: 3 data + 2 perspectives agents + 1 intuition. Pas 1 seul signal', 'ceo', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_32: Le retention early warning system: combiner 5 signaux (login frequency ↓, feature usage ↓, support tickets ↑, NPS ↓, payment issues) en 1 health score predictif.', 'Early warning: 5 signaux → 1 health score predictif churn', 'retention', 'best_practice', 0.88, 'adv_pack', 'system'),
('ADV_33: Le onboarding contextual help: afficher des tooltips d aide UNIQUEMENT quand l utilisateur semble perdu (hover long, clics multiples sans action, idle 30s).', 'Onboarding contextual help: tooltips quand perdu (hover long, clics sans action, idle)', 'onboarding', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_34: Le comptable tax planning: anticiper les obligations fiscales (TVA, IS, CFE) et provisionner chaque mois. Pas de surprise en fin d annee.', 'Tax planning: provisionner TVA+IS+CFE mensuellement. 0 surprise fin annee', 'comptable', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_35: Le RH feedback culture: normaliser le feedback continu (pas juste annuel). Format SBI: Situation + Behavior + Impact. Direct + bienveillant.', 'Feedback culture: SBI continu (Situation+Behavior+Impact). Direct + bienveillant', 'rh', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_36: Le marketing thought leadership: le fondateur publie 3x/semaine sur LinkedIn = +7x leads vs branding corporate. Le personal branding domine.', 'Thought leadership: fondateur 3x/sem LinkedIn = +7x leads vs corporate', 'marketing', 'insight', 0.85, 'adv_pack', 'system'),
('ADV_37: Le cross-agent opportunity detection: quand l agent email detecte un open rate > 50% pour un segment → alert le CEO → le commercial priorise ce segment → le contenu cree du contenu specifique.', 'Opportunity detection: email OR>50% segment → CEO → commercial priorise → contenu cree', NULL, 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_38: Le customer segmentation by behavior: power users (daily, multi-feature), regulars (weekly, core features), occasionals (monthly, 1 feature), at-risk (declining).', 'Segmentation behavior: power daily, regulars weekly, occasionals monthly, at-risk declining', NULL, 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_39: Le KeiroAI auto-improvement protocol: chaque agent analyse ses 10 meilleures et 10 pires executions du mois. Les patterns gagnants sont renforces, les perdants corriges.', 'Auto-improve: top 10 + bottom 10 executions/mois. Renforcer gagnants, corriger perdants', NULL, 'best_practice', 0.88, 'adv_pack', 'system'),
('ADV_40: Le KeiroAI client onboarding promise: premier agent actif en < 2 minutes. Premier contenu genere en < 60 secondes. Premier resultat mesurable en < 48h.', 'KeiroAI onboarding: agent <2min, contenu <60s, resultat <48h', 'onboarding', 'best_practice', 0.90, 'adv_pack', 'system'),
('ADV_41: Le email reply rate benchmarks: cold email B2B 3-8%, warm outreach 15-25%, customer email 30-50%. En dessous = revoir le contenu et le ciblage.', 'Reply rate: cold 3-8%, warm 15-25%, customer 30-50%', 'email', 'insight', 0.82, 'adv_pack', 'system'),
('ADV_42: Le commercial deal review questions: est-ce qu on a un champion? le budget est-il confirme? quelle est la competition? quel est le prochain milestone?', 'Deal review: champion? budget? competition? prochain milestone?', 'commercial', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_43: Le content AB testing method: meme message, 2 formats (carrousel vs video). Meme format, 2 hooks. Meme hook, 2 CTAs. Isoler 1 variable a la fois.', 'Content A/B: isoler 1 variable (format, hook, CTA). Pas tester tout en meme temps', 'content', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_44: Le SEO site architecture: homepage → categorie → sous-categorie → article. Maximum 3 clics entre n importe quelle page et la homepage.', 'SEO architecture: max 3 clics homepage → article. Categorie → sous-categorie', 'seo', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_45: Le ad scaling playbook: ROAS > 2x cible = +20%/jour. ROAS > cible = +10%. ROAS = cible = maintenir. ROAS < cible 3j = -30%. ROAS < breakeven = pause.', 'Scaling: >2x +20%, >cible +10%, =cible maintenir, <cible 3j -30%, <breakeven pause', 'ads', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_46: Le DM Instagram analytics: tracker response rate, conversation rate, RDV rate, conversion rate. Objectif: 30% response → 10% conversation → 3% RDV → 1% client.', 'DM analytics: 30% response → 10% conversation → 3% RDV → 1% client', 'dm_instagram', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_47: Le WhatsApp broadcast best practices: listes < 256 contacts, segmentees par interet, 1 message/semaine max, toujours avec opt-out, contenu de valeur pas juste promo.', 'WhatsApp broadcast: <256, segmente, 1/sem max, opt-out, valeur pas juste promo', 'whatsapp', 'best_practice', 0.85, 'adv_pack', 'system'),
('ADV_48: Le chatbot CSAT optimization: ajouter un survey 1 question apres chaque conversation (pouce haut/bas). Tracker par intent. Ameliorer les intents avec CSAT < 70%.', 'Chatbot CSAT: survey 1 question post-conv. Par intent. CSAT < 70% = ameliorer', 'chatbot', 'best_practice', 0.82, 'adv_pack', 'system'),
('ADV_49: Le GMaps seasonal updates: mettre a jour les horaires (fermetures, vacances), ajouter des photos saisonnieres, publier des posts lies a la saison.', 'GMaps seasonal: MAJ horaires + photos saisonnieres + posts saison', 'gmaps', 'best_practice', 0.80, 'adv_pack', 'system'),
('ADV_50: Le TikTok creator collaboration: identifier 5-10 createurs de sa niche (10-50K followers). Proposer une collaboration (produit offert contre video). ROI 5-10x vs ads.', 'TikTok collab: 5-10 createurs niche 10-50K. Produit contre video = ROI 5-10x vs ads', 'tiktok_comments', 'insight', 0.80, 'adv_pack', 'system')
